#include<bits/stdc++.h>
using namespace std;
int N;
struct node{
	string Name;
	int year,mon,day,level;
}man[10000];
bool cmp(node x,node y){
	if(x.year!=y.year)return x.year<y.year;
	if(x.mon!=y.mon)return x.mon<y.mon;
	if(x.day!=y.day)return x.day<y.day;
	return x.level>y.level;
}
int main(void){
	cin>>N;
	for(int i=0;i<N;i++)
		cin>>man[i].Name>>man[i].year>>man[i].mon>>man[i].day,man[i].level=i;
	sort(man,man+N,cmp);
	for(int i=0;i<N;i++)
		cout<<man[i].Name<<endl;
    return false;
}
